function l(){let s=document.getElementById("servings-display");if(!s)return;let c=parseInt(s.dataset.base??"1",10),n=c;function r(e){if(Number.isInteger(e))return e;let t=Math.round(e*10)/10;return Number.isInteger(t),t}function d(e){n=Math.max(1,n+e),s.textContent=String(n);let t=n/c;document.querySelectorAll(".scalable-value").forEach(a=>{let o=parseFloat(a.dataset.base??"0");a.textContent=String(r(o*t))}),document.querySelectorAll(".scalable-range").forEach(a=>{let o=parseFloat(a.dataset.baseLow??"0"),i=parseFloat(a.dataset.baseHigh??"0");a.textContent=`${r(o*t)}-${r(i*t)}`})}document.querySelectorAll(".servings-btn[data-delta]").forEach(e=>{let t=parseInt(e.dataset.delta??"0",10),a=()=>d(t);e.addEventListener("click",a),window.addCleanup(()=>e.removeEventListener("click",a))})}document.addEventListener("nav",l);
